/**
 * @file fft_radix2_avx512_dif_tw.h
 * @brief AVX512 DIF twiddled DFT-2 — notw butterfly + vectorized output twiddle
 *
 * Requires: radix2_notw_dit_kernel_{fwd,bwd}_avx512()
 * Include the notw AVX512 header before this file.
 * Generated by gen_small_dif_tw.py
 */

#ifndef FFT_RADIX2_AVX512_DIF_TW_H
#define FFT_RADIX2_AVX512_DIF_TW_H

#include <immintrin.h>
#include <stddef.h>

#ifdef FFT_RADIX2_AVX512_H
__attribute__((target("avx512f,avx512dq,fma")))
static inline void
radix2_tw_dif_kernel_fwd_avx512(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    const double * __restrict__ tw_re, const double * __restrict__ tw_im,
    size_t K)
{
    /* Pass 1: notw butterfly */
    radix2_notw_dit_kernel_fwd_avx512(in_re, in_im, out_re, out_im, K);
    /* Pass 2: apply twiddle to outputs 1..1 */
    for (size_t k = 0; k < K; k += 8) {
        { __m512d yr = _mm512_load_pd(&out_re[1*K+k]);
          __m512d yi = _mm512_load_pd(&out_im[1*K+k]);
          __m512d wr = _mm512_load_pd(&tw_re[0*K+k]);
          __m512d wi = _mm512_load_pd(&tw_im[0*K+k]);
          __m512d tr = yr;
          yr = _mm512_fmsub_pd(yr, wr, _mm512_mul_pd(yi, wi));
          yi = _mm512_fmadd_pd(tr, wi, _mm512_mul_pd(yi, wr));
          _mm512_store_pd(&out_re[1*K+k], yr);
          _mm512_store_pd(&out_im[1*K+k], yi); }
    }
}
#endif /* FFT_RADIX2_AVX512_H */

#ifdef FFT_RADIX2_AVX512_H
__attribute__((target("avx512f,avx512dq,fma")))
static inline void
radix2_tw_dif_kernel_bwd_avx512(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    const double * __restrict__ tw_re, const double * __restrict__ tw_im,
    size_t K)
{
    /* Pass 1: notw butterfly */
    radix2_notw_dit_kernel_bwd_avx512(in_re, in_im, out_re, out_im, K);
    /* Pass 2: apply twiddle to outputs 1..1 */
    for (size_t k = 0; k < K; k += 8) {
        { __m512d yr = _mm512_load_pd(&out_re[1*K+k]);
          __m512d yi = _mm512_load_pd(&out_im[1*K+k]);
          __m512d wr = _mm512_load_pd(&tw_re[0*K+k]);
          __m512d wi = _mm512_load_pd(&tw_im[0*K+k]);
          __m512d tr = yr;
          yr = _mm512_fmadd_pd(yr, wr, _mm512_mul_pd(yi, wi));
          yi = _mm512_fmsub_pd(yi, wr, _mm512_mul_pd(tr, wi));
          _mm512_store_pd(&out_re[1*K+k], yr);
          _mm512_store_pd(&out_im[1*K+k], yi); }
    }
}
#endif /* FFT_RADIX2_AVX512_H */

#endif /* FFT_RADIX2_AVX512_DIF_TW_H */
